mapper.select:
select * from `exam`

     and id = #{id}
     and course_id = #{courseId}
     and teacher_id = #{teacherId}
     and exam_type = #{examType}

order by id desc

mapper.update:
update `exam`
course_id = #{courseId}, teacher_id = #{teacherId}, exam_name = #{examName}, exam_type = #{examType}, exam_time = #{examTime}, total_score = #{totalScore}, duration_minutes = #{durationMinutes}, description = #{description}, create_time = #{createTime}, update_time = #{updateTime},
where id = #{id}
